import { useState } from "react";
import { ethers } from "ethers";
import axios from "axios"; // You might need to run: npm install axios

export default function IssueCertificate({ contractAddress, abi }) {
  const [formData, setFormData] = useState({ name: "", course: "", id: "" });
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);

  // YOUR PINATA JWT (Keep this secret in a .env file later!)
  const PINATA_JWT = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..w3xJwiAarQT4R0JFbeE4V9RA4EEO-u7zAJtZj2mSze8";

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  async function handleIssue() {
    if (!file) return alert("Please upload a certificate file first!");
    if (!window.ethereum) return alert("Please install MetaMask");

    try {
      setUploading(true);

      // 1. Upload File to IPFS via Pinata
      const formDataFile = new FormData();
      formDataFile.append("file", file);

      const res = await axios.post("https://api.pinata.cloud/pinning/pinFileToIPFS", formDataFile, {
        headers: {
          'Authorization': `Bearer ${PINATA_JWT}`,
          'Content-Type': 'multipart/form-data'
        }
      });

      const ipfsHash = res.data.IpfsHash;
      console.log("File uploaded to IPFS:", ipfsHash);

      // 2. Interact with Smart Contract
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      const signer = provider.getSigner();
      const contract = new ethers.Contract(contractAddress, abi, signer);

      const certIdBytes = ethers.utils.formatBytes32String(formData.id);
      
      const tx = await contract.issueCertificate(
        formData.name, 
        formData.course, 
        ipfsHash, 
        certIdBytes
      );

      await tx.wait();
      alert("Certificate Issued & File Uploaded Successfully!");
      setUploading(false);
    } catch (error) {
      console.error(error);
      alert("Error: " + error.message);
      setUploading(false);
    }
  }

  return (
    <div className="card">
      <h3>Issue New Certificate</h3>
      <input placeholder="Student Name" onChange={e => setFormData({...formData, name: e.target.value})} />
      <input placeholder="Course" onChange={e => setFormData({...formData, course: e.target.value})} />
      <input placeholder="Unique ID" onChange={e => setFormData({...formData, id: e.target.value})} />
      
      <label style={{marginTop: "10px", fontSize: "0.8rem", color: "var(--text-muted)"}}>Upload Document (PDF/JPG):</label>
      <input type="file" onChange={handleFileChange} style={{border: "none", background: "none"}} />
      
      <button onClick={handleIssue} disabled={uploading}>
        {uploading ? "Uploading to IPFS..." : "Mint on Blockchain"}
      </button>
    </div>
  );
}
